using UnityEngine;
public class Script {
  public static object Main() {
    var sb = new System.Text.StringBuilder();
    var buttons = GameObject.FindObjectsByType<CNC3DButton>(FindObjectsSortMode.None);
    sb.AppendLine("Fixing " + buttons.Length + " CNC3DButton colliders...");

    foreach (var btn in buttons) {
      var box = btn.GetComponent<BoxCollider>();
      if (box == null) { sb.AppendLine(btn.gameObject.name + ": no BoxCollider, skipping"); continue; }

      // Find the deepest mesh renderer to get true visual bounds
      MeshRenderer bestRenderer = null;
      float bestVol = -1f;
      foreach (var mr in btn.GetComponentsInChildren<MeshRenderer>()) {
        float vol = mr.bounds.size.x * mr.bounds.size.y * mr.bounds.size.z;
        if (vol > bestVol) { bestVol = vol; bestRenderer = mr; }
      }

      if (bestRenderer == null) {
        sb.AppendLine(btn.gameObject.name + ": no MeshRenderer");
        continue;
      }

      Bounds wb = bestRenderer.bounds;
      Vector3 ls = btn.transform.lossyScale;

      // Local center in collider's own space
      Vector3 localCenter = btn.transform.InverseTransformPoint(wb.center);

      // Local size = world size / lossy scale
      Vector3 localSize = new Vector3(
        wb.size.x / Mathf.Abs(ls.x),
        wb.size.y / Mathf.Abs(ls.y),
        wb.size.z / Mathf.Abs(ls.z));

      // Add 20% padding so raycast hits comfortably
      localSize *= 1.2f;

      box.center = localCenter;
      box.size   = localSize;

      sb.AppendLine(btn.gameObject.name
        + "  worldBounds=" + wb.size.ToString("F3")
        + "  lossyScale=" + ls.ToString("F3")
        + "  => localSize=" + localSize.ToString("F3")
        + "  localCenter=" + localCenter.ToString("F3"));
    }
    return sb.ToString();
  }
}
